import json
import sys

def run(payload):
    text = payload.get('text', '').lower()
    controls = ['access control', 'change management', 'incident response', 'vendor management']
    return {'matches': [c for c in controls if c in text]}

if __name__ == '__main__':
    print(json.dumps(run(json.load(sys.stdin))))
